// Package clients contains Connect client adapters for peer services.
package clients

import (
	"context"
	"net/http"

	"connectrpc.com/connect"

	// Generated by buf generate
	soilv1 "p9e.in/samavaya/agriculture/soil-service/api/v1"
	soilv1connect "p9e.in/samavaya/agriculture/soil-service/api/v1/soilv1connect"
	"p9e.in/samavaya/agriculture/yield-service/internal/ports/outbound"
)

type soilClient struct {
	client soilv1connect.SoilServiceClient
}

// NewSoilClient creates a Connect-backed SoilClient.
func NewSoilClient(baseURL string, httpClient *http.Client, opts ...connect.ClientOption) outbound.SoilClient {
	return &soilClient{
		client: soilv1connect.NewSoilServiceClient(httpClient, baseURL, opts...),
	}
}

func (c *soilClient) SoilExists(ctx context.Context, uuid, tenantID string) (bool, error) {
	resp, err := c.client.GetSoil(ctx, connect.NewRequest(&soilv1.GetSoilRequest{Id: uuid}))
	if err != nil {
		return false, nil
	}
	return resp.Msg.GetSoil() != nil, nil
}

func (c *soilClient) GetLatestAnalysis(ctx context.Context, fieldUUID, tenantID string) (float64, error) {
	resp, err := c.client.GetLatestAnalysis(ctx, connect.NewRequest(&soilv1.GetLatestAnalysisRequest{FieldId: fieldUUID}))
	if err != nil {
		return 0, err
	}
	return resp.Msg.GetHealthScore(), nil
}
